/**
 * @param {number} hour
 * @param {number} minutes
 * @return {number}
 */
var angleClock = function(hour, minutes) {
    const betweenMinutes = minutes * 6;
    const betweenHour = hour * 30 + (minutes / 2);
    const diff = Math.abs(betweenMinutes - betweenHour);

    return Math.min(diff, 360 - diff);
};
